package com.schoolbus.dto.response;
import com.schoolbus.entity.*; import java.time.*;
public record AssignmentResponse(Long id,String type,Long driverId,String driverName,Long studentId,String studentName,Long busId,String busNumber,Long routeId,String routeName,Boolean active,String assignedAt){public static AssignmentResponse driver(DriverBus x){return new AssignmentResponse(x.getId(),"DRIVER",x.getDriver().getId(),x.getDriver().getUser().getFullName(),null,null,x.getBus().getId(),x.getBus().getBusNumber(),x.getRoute()==null?null:x.getRoute().getId(),x.getRoute()==null?null:x.getRoute().getName(),x.getActive(),x.getAssignedFrom().toString());}public static AssignmentResponse student(StudentBus x){return new AssignmentResponse(x.getId(),"STUDENT",null,null,x.getStudent().getId(),x.getStudent().getFullName(),x.getBus().getId(),x.getBus().getBusNumber(),x.getRoute()==null?null:x.getRoute().getId(),x.getRoute()==null?null:x.getRoute().getName(),x.getActive(),x.getAssignedFrom().toString());}}
